import React, { useEffect, useState } from 'react';
import { useAuth } from '@/context/AuthContext';
import { dashboardApi } from '@/lib/api';
import { AlertCircle } from 'lucide-react';

const UrgentAlerts = () => {
    const { user } = useAuth();
    const [alerts, setAlerts] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchAlerts = async () => {
            if (!user) return;
            try {
                const token = await user.getIdToken();
                const data = await dashboardApi.getAlerts(token);
                setAlerts(data);
            } catch (error) {
                console.error('Error fetching dashboard alerts:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchAlerts();
    }, [user]);

    if (loading) {
        return (
            <div className="card border-0 shadow-sm rounded-2xl bg-white overflow-hidden">
                <div className="card-header bg-white border-0 p-4 pb-0">
                    <div className="placeholder col-6 rounded py-2"></div>
                </div>
                <div className="card-body p-4 pt-4">
                    {[1, 2].map(i => (
                        <div key={i} className="d-flex align-items-start gap-3 mb-3 placeholder-glow">
                            <div className="placeholder rounded-circle" style={{ width: '32px', height: '32px' }}></div>
                            <div className="flex-grow-1">
                                <div className="placeholder col-10 rounded mb-1"></div>
                                <div className="placeholder col-8 rounded"></div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="card border-0 shadow-sm rounded-2xl bg-white overflow-hidden">
            <div className="card-header bg-white border-0 p-4 pb-0 d-flex align-items-center justify-content-between">
                <h3 className="h6 fw-extrabold text-dark mb-0 text-uppercase tracking-wider" style={{ fontSize: '14px' }}>Urgent Alerts</h3>
                <span className="badge bg-danger bg-opacity-10 text-danger rounded-pill px-3 py-2 fw-bold" style={{ fontSize: '10px' }}>{alerts.length} NEW</span>
            </div>
            <div className="card-body p-4 pt-4">
                <div className="d-flex flex-column gap-3">
                    {alerts.length > 0 ? alerts.map((alert, index) => (
                        <div key={index} className="d-flex align-items-start gap-3 p-3 rounded-xl hover-bg-light transition-300 cursor-pointer border border-light">
                            <div className="p-2 rounded-circle bg-danger bg-opacity-10 text-danger d-flex align-items-center justify-content-center mt-1">
                                <AlertCircle size={16} />
                            </div>
                            <div className="flex-grow-1">
                                <h5 className="h6 fw-bold text-dark mb-1" style={{ fontSize: '13px' }}>{alert.title}</h5>
                                <p className="text-muted mb-1 overflow-hidden text-truncate-2" style={{ fontSize: '12px', lineHeight: '1.4' }}>{alert.desc}</p>
                                <span className="text-secondary opacity-50" style={{ fontSize: '10px', fontWeight: '500' }}>{alert.time}</span>
                            </div>
                        </div>
                    )) : (
                        <div className="text-center py-4">
                            <p className="text-muted small mb-0">No urgent alerts at this time</p>
                        </div>
                    )}
                </div>
                <button className="btn btn-link link-teal-600 w-100 mt-4 text-decoration-none fw-bold shadow-none p-0" style={{ fontSize: '13px' }}>
                    View All Alerts
                </button>
            </div>
        </div>
    );
};

export default UrgentAlerts;
